import { EventBus } from '../event-bus';

describe('EventBus', () => {
  let bus: EventBus;

  beforeEach(() => {
    bus = new EventBus();
  });

  test('on and emit calls handler', () => {
    const calls: string[] = [];
    bus.on('greet', (name: string) => calls.push(name));
    bus.emit('greet', 'Alice');
    expect(calls).toEqual(['Alice']);
  });

  test('multiple listeners all called', () => {
    let a = 0, b = 0;
    bus.on('tick', () => a++);
    bus.on('tick', () => b++);
    bus.emit('tick');
    expect(a).toBe(1);
    expect(b).toBe(1);
  });

  test('off removes handler', () => {
    const calls: number[] = [];
    const handler = () => calls.push(1);
    bus.on('event', handler);
    bus.emit('event');
    bus.off('event', handler);
    bus.emit('event');
    expect(calls).toEqual([1]);
  });

  test('once fires only once', () => {
    let count = 0;
    bus.once('init', () => count++);
    bus.emit('init');
    bus.emit('init');
    bus.emit('init');
    expect(count).toBe(1);
  });

  test('emit passes arguments', () => {
    let received: any[] = [];
    bus.on('data', (...args) => { received = args; });
    bus.emit('data', 1, 'two', true);
    expect(received).toEqual([1, 'two', true]);
  });

  test('emit unknown event does nothing', () => {
    expect(() => bus.emit('nonexistent')).not.toThrow();
  });
});
